168→		client := &http.Client{
169→			Transport: transport,
170→			Timeout:   DefaultTimeout,
171→			CheckRedirect: func(_ *http.Request, _ []*http.Request) error {
172→				return http.ErrUseLastResponse
173→			},
174→		}
175→
176→		resp, err := client.Do(req)
177→		if err != nil {
178→			return nil, fmt.Errorf("safefetch: http: %w", err)
179→		}
180→
181→		// Handle redirects manually
182→		if isRedirect(resp.StatusCode) {
183→			_ = resp.Body.Close()
184→			redirectCount++
185→			if redirectCount > maxRedirects {
186→				return nil, ErrTooManyRedirects
187→			}
188→
189→			loc := resp.Header.Get("Location")
190→			if loc == "" {
191→				return nil, fmt.Errorf("safefetch: redirect with no Location header")
192→			}
193→
194→			redirectURL, err := req.URL.Parse(loc)
195→			if err != nil {
196→				return nil, fmt.Errorf("safefetch: invalid redirect URL: %w", err)
197→			}
198→
199→			req, err = http.NewRequestWithContext(ctx, http.MethodGet, redirectURL.String(), nil)
200→			if err != nil {
201→				return nil, fmt.Errorf("safefetch: build redirect request: %w", err)
202→			}
203→			continue
204→		}
205→
206→		// Validate content type
207→		ct := resp.Header.Get("Content-Type")
208→		if ct != "" && !isAllowedContentType(ct) {
209→			_ = resp.Body.Close()
210→			return nil, fmt.Errorf("%w: %s", ErrBlockedContentType, ct)
211→		}
212→
213→		// Cap response body size
214→		resp.Body = io.NopCloser(io.LimitReader(resp.Body, c.maxResponseBytes))
215→		return resp, nil
216→	}
217→}
