// Package safefetch provides an SSRF-safe HTTP client that validates URLs
// before fetching. It blocks private/loopback/link-local IP addresses,
// non-HTTP(S) schemes, and caps response sizes.
package safefetch

import (
	"context"
	"errors"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"
)

const (
	// DefaultTimeout is the default HTTP client timeout.
	DefaultTimeout = 30 * time.Second

	// DefaultMaxResponseBytes is the maximum response body size (10 MB).
	DefaultMaxResponseBytes = 10 * 1024 * 1024

	// maxRedirects is the maximum number of redirects to follow.
	maxRedirects = 10
)

// allowedSchemes are the only URL schemes permitted for fetching.
var allowedSchemes = map[string]bool{
	"http":  true,
	"https": true,
}

// blockedNets are CIDR ranges that must never be fetched.
var blockedNets []*net.IPNet

func init() {
	cidrs := []string{
		"127.0.0.0/8",    // IPv4 loopback
		"10.0.0.0/8",     // RFC 1918
		"172.16.0.0/12",  // RFC 1918
		"192.168.0.0/16", // RFC 1918
		"169.254.0.0/16", // link-local
		"0.0.0.0/8",      // unspecified / "this" network
		"100.64.0.0/10",  // shared address space (CGNAT)
		"192.0.0.0/24",   // IETF protocol assignments
		"192.0.2.0/24",   // TEST-NET-1
		"198.51.100.0/24", // TEST-NET-2
		"203.0.113.0/24", // TEST-NET-3
		"224.0.0.0/4",    // multicast
		"240.0.0.0/4",    // reserved
		"::1/128",        // IPv6 loopback
		"fc00::/7",       // IPv6 unique local
		"fe80::/10",      // IPv6 link-local
		"ff00::/8",       // IPv6 multicast
		"::/128",         // IPv6 unspecified
	}
	for _, cidr := range cidrs {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			panic(fmt.Sprintf("safefetch: invalid CIDR %q: %v", cidr, err))
		}
		blockedNets = append(blockedNets, ipNet)
	}
}

// allowedContentTypes are Content-Type prefixes we accept.
var allowedContentTypes = []string{
	"text/",
	"application/xhtml",
	"application/xml",
	"application/json",
}

var (
	// ErrBlockedScheme is returned when the URL uses a non-HTTP(S) scheme.
	ErrBlockedScheme = errors.New("safefetch: blocked scheme")

	// ErrBlockedIP is returned when the resolved IP is in a blocked range.
	ErrBlockedIP = errors.New("safefetch: blocked IP address")

	// ErrBlockedContentType is returned when the response Content-Type is not allowed.
	ErrBlockedContentType = errors.New("safefetch: blocked content type")

	// ErrTooManyRedirects is returned when the redirect limit is exceeded.
	ErrTooManyRedirects = errors.New("safefetch: too many redirects")

	// ErrEmptyHost is returned when the URL has no hostname.
	ErrEmptyHost = errors.New("safefetch: empty host")
)

// Resolver resolves hostnames to IP addresses. Matches net.Resolver.LookupIPAddr.
type Resolver interface {
	LookupIPAddr(ctx context.Context, host string) ([]net.IPAddr, error)
}

// Option configures a Client.
type Option func(*Client)

// WithResolver overrides the DNS resolver (useful for testing).
func WithResolver(r Resolver) Option {
	return func(c *Client) { c.resolver = r }
}

// WithMaxResponseBytes overrides the response body size cap.
func WithMaxResponseBytes(n int64) Option {
	return func(c *Client) { c.maxResponseBytes = n }
}

// WithTransport sets the base HTTP transport (useful for testing with httptest).
func WithTransport(t http.RoundTripper) Option {
	return func(c *Client) { c.baseTransport = t }
}

// Client is an SSRF-safe HTTP client.
type Client struct {
	resolver         Resolver
	maxResponseBytes int64
	baseTransport    http.RoundTripper
}

// NewClient creates a new SSRF-safe HTTP client.
func NewClient(opts ...Option) *Client {
	c := &Client{
		resolver:         net.DefaultResolver,
		maxResponseBytes: DefaultMaxResponseBytes,
		baseTransport:    http.DefaultTransport,
	}
	for _, opt := range opts {
		opt(c)
	}
	return c
}

// Do performs an SSRF-safe HTTP request. It validates the URL scheme, resolves
// DNS, checks all resolved IPs against blocked ranges, pins the connection to
// the resolved IP, follows redirects safely, and caps the response body size.
func (c *Client) Do(ctx context.Context, req *http.Request) (*http.Response, error) {
	redirectCount := 0

	for {
		// Validate scheme
		if !allowedSchemes[req.URL.Scheme] {
			return nil, fmt.Errorf("%w: %s", ErrBlockedScheme, req.URL.Scheme)
		}

		// Resolve and validate the target IP
		host := req.URL.Hostname()
		if host == "" {
			return nil, ErrEmptyHost
		}

		ip, err := c.resolveAndValidate(ctx, host)
		if err != nil {
			return nil, err
		}

		// Use pinned transport in production; use injected transport for tests
		var transport http.RoundTripper
		if c.baseTransport != http.DefaultTransport {
			transport = c.baseTransport
		} else {
			transport = c.pinnedTransport(ip, req.URL.Port())
		}

		// Disable automatic redirects — we handle them manually to re-validate IPs
		client := &http.Client{
			Transport: transport,
			Timeout:   DefaultTimeout,
			CheckRedirect: func(_ *http.Request, _ []*http.Request) error {
				return http.ErrUseLastResponse
			},
		}

		resp, err := client.Do(req)
		if err != nil {
			return nil, fmt.Errorf("safefetch: http: %w", err)
		}

		// Handle redirects manually
		if isRedirect(resp.StatusCode) {
			_ = resp.Body.Close()
			redirectCount++
			if redirectCount > maxRedirects {
				return nil, ErrTooManyRedirects
			}

			loc := resp.Header.Get("Location")
			if loc == "" {
				return nil, fmt.Errorf("safefetch: redirect with no Location header")
			}

			redirectURL, err := req.URL.Parse(loc)
			if err != nil {
				return nil, fmt.Errorf("safefetch: invalid redirect URL: %w", err)
			}

			req, err = http.NewRequestWithContext(ctx, http.MethodGet, redirectURL.String(), nil)
			if err != nil {
				return nil, fmt.Errorf("safefetch: build redirect request: %w", err)
			}
			continue
		}

		// Validate content type
		ct := resp.Header.Get("Content-Type")
		if ct != "" && !isAllowedContentType(ct) {
			_ = resp.Body.Close()
			return nil, fmt.Errorf("%w: %s", ErrBlockedContentType, ct)
		}

		// Cap response body size
		resp.Body = io.NopCloser(io.LimitReader(resp.Body, c.maxResponseBytes))
		return resp, nil
	}
}

// ValidateURL checks a URL string for SSRF safety without making a request.
func (c *Client) ValidateURL(ctx context.Context, rawURL string) error {
	u, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("safefetch: invalid URL: %w", err)
	}
	if !allowedSchemes[u.Scheme] {
		return fmt.Errorf("%w: %s", ErrBlockedScheme, u.Scheme)
	}
	host := u.Hostname()
	if host == "" {
		return ErrEmptyHost
	}
	_, err = c.resolveAndValidate(ctx, host)
	return err
}

// resolveAndValidate resolves a hostname and checks all IPs against blocked ranges.
// Returns the first valid IP for pinning.
func (c *Client) resolveAndValidate(ctx context.Context, host string) (net.IP, error) {
	// If the host is already an IP literal, check it directly
	if ip := net.ParseIP(host); ip != nil {
		if isBlockedIP(ip) {
			return nil, fmt.Errorf("%w: %s", ErrBlockedIP, ip)
		}
		return ip, nil
	}

	addrs, err := c.resolver.LookupIPAddr(ctx, host)
	if err != nil {
		return nil, fmt.Errorf("safefetch: dns lookup %q: %w", host, err)
	}
	if len(addrs) == 0 {
		return nil, fmt.Errorf("safefetch: dns lookup %q: no addresses", host)
	}

	// ALL resolved IPs must be safe (attacker could use round-robin DNS)
	for _, addr := range addrs {
		if isBlockedIP(addr.IP) {
			return nil, fmt.Errorf("%w: %s resolves to %s", ErrBlockedIP, host, addr.IP)
		}
	}

	return addrs[0].IP, nil
}

// pinnedTransport returns an HTTP transport that connects to a specific IP,
// preventing TOCTOU between DNS resolution and connection.
func (c *Client) pinnedTransport(ip net.IP, port string) *http.Transport {
	if port == "" {
		port = "80"
	}
	addr := net.JoinHostPort(ip.String(), port)

	return &http.Transport{
		DialContext: func(ctx context.Context, network, _ string) (net.Conn, error) {
			dialer := &net.Dialer{Timeout: 10 * time.Second}
			return dialer.DialContext(ctx, network, addr)
		},
		// Disable TLS for pinned transport — we connect by IP but the TLS
		// handshake uses the original hostname from the request.
		TLSHandshakeTimeout: 10 * time.Second,
		DisableKeepAlives:   true,
	}
}

// isBlockedIP returns true if the IP falls in any blocked CIDR range.
// It normalizes IPv4-mapped IPv6 addresses (::ffff:x.x.x.x) to IPv4
// before checking, so that e.g. ::ffff:127.0.0.1 is correctly blocked.
func isBlockedIP(ip net.IP) bool {
	// Normalize IPv4-mapped IPv6 to plain IPv4
	if v4 := ip.To4(); v4 != nil {
		ip = v4
	}
	for _, n := range blockedNets {
		if n.Contains(ip) {
			return true
		}
	}
	return false
}

func isRedirect(code int) bool {
	return code == 301 || code == 302 || code == 303 || code == 307 || code == 308
}

func isAllowedContentType(ct string) bool {
	ct = strings.ToLower(strings.TrimSpace(ct))
	for _, prefix := range allowedContentTypes {
		if strings.HasPrefix(ct, prefix) {
			return true
		}
	}
	return false
}

