  5→	"fmt"
  6→	"io"
  7→	"net"
  8→	"net/http"
  9→	"net/http/httptest"
 10→	"strings"
 11→	"testing"
 12→)
 13→
 14→// mockResolver returns predefined IPs for any hostname lookup.
 15→type mockResolver struct {
 16→	addrs []net.IPAddr
 17→	err   error
 18→}
 19→
 20→func (m *mockResolver) LookupIPAddr(_ context.Context, _ string) ([]net.IPAddr, error) {
 21→	return m.addrs, m.err
 22→}
 23→
 24→func newMockResolver(ips ...string) *mockResolver {
 25→	var addrs []net.IPAddr
 26→	for _, s := range ips {
 27→		addrs = append(addrs, net.IPAddr{IP: net.ParseIP(s)})
 28→	}
 29→	return &mockResolver{addrs: addrs}
 30→}
 31→
 32→// publicResolver returns a safe public IP so httptest servers pass DNS validation.
 33→var publicResolver = newMockResolver("93.184.216.34")
 34→
 35→// localDialTransport creates an http.Transport that always dials the given
 36→// address regardless of the requested host. This lets us use fake hostnames
 37→// in test URLs while still connecting to the httptest server.
 38→func localDialTransport(addr string) *http.Transport {
 39→	return &http.Transport{
 40→		DialContext: func(ctx context.Context, network, _ string) (net.Conn, error) {
 41→			return (&net.Dialer{}).DialContext(ctx, network, addr)
 42→		},
 43→	}
 44→}
 45→
 46→// testClient creates a safefetch.Client configured for httptest servers:
 47→// uses a transport that always dials the httptest server and a mock resolver
 48→// returning a public IP so DNS validation passes.
 49→func testClient(srv *httptest.Server, opts ...Option) *Client {
 50→	// Extract the actual server address (127.0.0.1:PORT)
 51→	addr := strings.TrimPrefix(srv.URL, "http://")
 52→	base := []Option{
 53→		WithTransport(localDialTransport(addr)),
 54→		WithResolver(publicResolver),
 55→	}
 56→	return NewClient(append(base, opts...)...)
