package safefetch

import (
	"context"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

// mockResolver returns predefined IPs for any hostname lookup.
type mockResolver struct {
	addrs []net.IPAddr
	err   error
}

func (m *mockResolver) LookupIPAddr(_ context.Context, _ string) ([]net.IPAddr, error) {
	return m.addrs, m.err
}

func newMockResolver(ips ...string) *mockResolver {
	var addrs []net.IPAddr
	for _, s := range ips {
		addrs = append(addrs, net.IPAddr{IP: net.ParseIP(s)})
	}
	return &mockResolver{addrs: addrs}
}

// publicResolver returns a safe public IP so httptest servers pass DNS validation.
var publicResolver = newMockResolver("93.184.216.34")

// localDialTransport creates an http.Transport that always dials the given
// address regardless of the requested host. This lets us use fake hostnames
// in test URLs while still connecting to the httptest server.
func localDialTransport(addr string) *http.Transport {
	return &http.Transport{
		DialContext: func(ctx context.Context, network, _ string) (net.Conn, error) {
			return (&net.Dialer{}).DialContext(ctx, network, addr)
		},
	}
}

// testClient creates a safefetch.Client configured for httptest servers:
// uses a transport that always dials the httptest server and a mock resolver
// returning a public IP so DNS validation passes.
func testClient(srv *httptest.Server, opts ...Option) *Client {
	// Extract the actual server address (127.0.0.1:PORT)
	addr := strings.TrimPrefix(srv.URL, "http://")
	base := []Option{
		WithTransport(localDialTransport(addr)),
		WithResolver(publicResolver),
	}
	return NewClient(append(base, opts...)...)
}

// testURL rewrites an httptest server URL to use a hostname instead of
// 127.0.0.1, so it goes through DNS resolution (which hits the mock resolver).
func testURL(srvURL string, path string) string {
	return strings.Replace(srvURL, "127.0.0.1", "test.local", 1) + path
}

func TestBlockedSchemes(t *testing.T) {
	schemes := []string{"file", "ftp", "gopher", "javascript", "data", "dict"}
	c := NewClient()

	for _, scheme := range schemes {
		t.Run(scheme, func(t *testing.T) {
			err := c.ValidateURL(context.Background(), scheme+"://example.com/path")
			if err == nil {
				t.Fatal("expected error for blocked scheme")
			}
			if !strings.Contains(err.Error(), "blocked scheme") {
				t.Errorf("expected blocked scheme error, got: %v", err)
			}
		})
	}
}

func TestAllowedSchemes(t *testing.T) {
	c := NewClient(WithResolver(newMockResolver("93.184.216.34")))

	for _, scheme := range []string{"http", "https"} {
		t.Run(scheme, func(t *testing.T) {
			err := c.ValidateURL(context.Background(), scheme+"://example.com/path")
			if err != nil {
				t.Fatalf("unexpected error for allowed scheme %s: %v", scheme, err)
			}
		})
	}
}

func TestBlockedIPLiterals(t *testing.T) {
	cases := []struct {
		name string
		url  string
	}{
		{"loopback_v4", "http://127.0.0.1/"},
		{"loopback_v4_alt", "http://127.0.0.2/"},
		{"loopback_v6", "http://[::1]/"},
		{"private_10", "http://10.0.0.1/"},
		{"private_172", "http://172.16.0.1/"},
		{"private_192", "http://192.168.1.1/"},
		{"link_local", "http://169.254.169.254/"},
		{"unspecified_v4", "http://0.0.0.0/"},
		{"unspecified_v6", "http://[::]/"},
		{"multicast_v4", "http://224.0.0.1/"},
		{"multicast_v6", "http://[ff02::1]/"},
		{"unique_local_v6", "http://[fd00::1]/"},
		{"link_local_v6", "http://[fe80::1]/"},
		{"cgnat", "http://100.64.0.1/"},
	}

	c := NewClient()
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			err := c.ValidateURL(context.Background(), tc.url)
			if err == nil {
				t.Fatalf("expected error for blocked IP in %s", tc.url)
			}
			if !strings.Contains(err.Error(), "blocked IP") {
				t.Errorf("expected blocked IP error, got: %v", err)
			}
		})
	}
}

func TestBlockedDNSResolution(t *testing.T) {
	cases := []struct {
		name string
		ips  []string
	}{
		{"resolves_to_loopback", []string{"127.0.0.1"}},
		{"resolves_to_private", []string{"10.0.0.1"}},
		{"resolves_to_link_local", []string{"169.254.169.254"}},
		{"mixed_public_and_private", []string{"93.184.216.34", "10.0.0.1"}},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			c := NewClient(WithResolver(newMockResolver(tc.ips...)))
			err := c.ValidateURL(context.Background(), "http://evil.example.com/")
			if err == nil {
				t.Fatal("expected error for blocked DNS resolution")
			}
			if !strings.Contains(err.Error(), "blocked IP") {
				t.Errorf("expected blocked IP error, got: %v", err)
			}
		})
	}
}

func TestPublicIPAllowed(t *testing.T) {
	c := NewClient(WithResolver(newMockResolver("93.184.216.34")))
	err := c.ValidateURL(context.Background(), "http://example.com/")
	if err != nil {
		t.Fatalf("unexpected error for public IP: %v", err)
	}
}

func TestEmptyHost(t *testing.T) {
	c := NewClient()
	err := c.ValidateURL(context.Background(), "http:///path")
	if err == nil {
		t.Fatal("expected error for empty host")
	}
}

func TestSuccessfulFetch(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "text/html")
		_, _ = w.Write([]byte("<html><body>Hello</body></html>"))
	}))
	defer srv.Close()

	c := testClient(srv)
	req, _ := http.NewRequestWithContext(context.Background(), http.MethodGet, testURL(srv.URL, ""), nil)
	resp, err := c.Do(context.Background(), req)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	defer func() { _ = resp.Body.Close() }()

	body, _ := io.ReadAll(resp.Body)
	if !strings.Contains(string(body), "Hello") {
		t.Errorf("unexpected body: %s", body)
	}
}

func TestResponseSizeLimit(t *testing.T) {
	maxBytes := int64(100)
	bigBody := strings.Repeat("X", 500)

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "text/plain")
		_, _ = w.Write([]byte(bigBody))
	}))
	defer srv.Close()

	c := testClient(srv, WithMaxResponseBytes(maxBytes))
	req, _ := http.NewRequestWithContext(context.Background(), http.MethodGet, testURL(srv.URL, ""), nil)
	resp, err := c.Do(context.Background(), req)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	defer func() { _ = resp.Body.Close() }()

	body, _ := io.ReadAll(resp.Body)
	if int64(len(body)) > maxBytes {
		t.Errorf("body length %d exceeds max %d", len(body), maxBytes)
	}
}

func TestBlockedContentType(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.Header().Set("Content-Type", "application/octet-stream")
		_, _ = w.Write([]byte("binary data"))
	}))
	defer srv.Close()

	c := testClient(srv)
	req, _ := http.NewRequestWithContext(context.Background(), http.MethodGet, testURL(srv.URL, ""), nil)
	_, err := c.Do(context.Background(), req)
	if err == nil {
		t.Fatal("expected error for blocked content type")
	}
	if !strings.Contains(err.Error(), "blocked content type") {
		t.Errorf("expected blocked content type error, got: %v", err)
	}
}

func TestAllowedContentTypes(t *testing.T) {
	types := []string{"text/html", "text/plain", "application/xhtml+xml", "application/xml", "application/json"}

	for _, ct := range types {
		t.Run(ct, func(t *testing.T) {
			srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
				w.Header().Set("Content-Type", ct)
				_, _ = w.Write([]byte("content"))
			}))
			defer srv.Close()

			c := testClient(srv)
			req, _ := http.NewRequestWithContext(context.Background(), http.MethodGet, testURL(srv.URL, ""), nil)
			resp, err := c.Do(context.Background(), req)
			if err != nil {
				t.Fatalf("unexpected error for content type %s: %v", ct, err)
			}
			_ = resp.Body.Close()
		})
	}
}

func TestRedirectToBlockedIP(t *testing.T) {
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		http.Redirect(w, r, "http://127.0.0.1/secret", http.StatusFound)
	}))
	defer srv.Close()

	c := testClient(srv)
	req, _ := http.NewRequestWithContext(context.Background(), http.MethodGet, testURL(srv.URL, ""), nil)
