package safefetch

import (
	"context"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

// mockResolver returns predefined IPs for any hostname lookup.
type mockResolver struct {
	addrs []net.IPAddr
	err   error
}

func (m *mockResolver) LookupIPAddr(_ context.Context, _ string) ([]net.IPAddr, error) {
	return m.addrs, m.err
}

func newMockResolver(ips ...string) *mockResolver {
	var addrs []net.IPAddr
	for _, s := range ips {
		addrs = append(addrs, net.IPAddr{IP: net.ParseIP(s)})
	}
	return &mockResolver{addrs: addrs}
}

// publicResolver returns a safe public IP so httptest servers pass DNS validation.
var publicResolver = newMockResolver("93.184.216.34")

// localDialTransport creates an http.Transport that always dials the given
// address regardless of the requested host. This lets us use fake hostnames
// in test URLs while still connecting to the httptest server.
func localDialTransport(addr string) *http.Transport {
	return &http.Transport{
		DialContext: func(ctx context.Context, network, _ string) (net.Conn, error) {
			return (&net.Dialer{}).DialContext(ctx, network, addr)
		},
	}
}

// testClient creates a safefetch.Client configured for httptest servers:
// uses a transport that always dials the httptest server and a mock resolver
// returning a public IP so DNS validation passes.
func testClient(srv *httptest.Server, opts ...Option) *Client {
	// Extract the actual server address (127.0.0.1:PORT)
	addr := strings.TrimPrefix(srv.URL, "http://")
	base := []Option{
		WithTransport(localDialTransport(addr)),
		WithResolver(publicResolver),
	}
	return NewClient(append(base, opts...)...)
}

// testURL rewrites an httptest server URL to use a hostname instead of
// 127.0.0.1, so it goes through DNS resolution (which hits the mock resolver).
func testURL(srvURL string, path string) string {
	return strings.Replace(srvURL, "127.0.0.1", "test.local", 1) + path
}

func TestBlockedSchemes(t *testing.T) {
	schemes := []string{"file", "ftp", "gopher", "javascript", "data", "dict"}
	c := NewClient()

	for _, scheme := range schemes {
		t.Run(scheme, func(t *testing.T) {
			err := c.ValidateURL(context.Background(), scheme+"://example.com/path")
			if err == nil {
				t.Fatal("expected error for blocked scheme")
			}
			if !strings.Contains(err.Error(), "blocked scheme") {
				t.Errorf("expected blocked scheme error, got: %v", err)
			}
		})
	}
}

func TestAllowedSchemes(t *testing.T) {
	c := NewClient(WithResolver(newMockResolver("93.184.216.34")))

	for _, scheme := range []string{"http", "https"} {
		t.Run(scheme, func(t *testing.T) {
			err := c.ValidateURL(context.Background(), scheme+"://example.com/path")
			if err != nil {
				t.Fatalf("unexpected error for allowed scheme %s: %v", scheme, err)
			}
		})
	}
}

