		{"empty_scheme_no_port", "", "", "80"},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			tr := c.pinnedTransport(ip, tc.port, tc.scheme)
			// Verify by dialing — the transport's DialContext captures the addr.
